const cfg     = $('Config').first().json;
const payload = $('Webhook').first().json.body;
const cfg2    = payload.config || {};

const tzOff  = parseInt(cfg.TZ_OFFSET_HOURS, 10);
const hStart = cfg2.working_hours_start ? parseInt(cfg2.working_hours_start.split(':')[0], 10) : 9;
const hEnd   = cfg2.working_hours_end   ? parseInt(cfg2.working_hours_end.split(':')[0],   10) : 19;

const nowUtc   = new Date();
const nowLocal = new Date(nowUtc.getTime() + tzOff * 3600 * 1000);
const hour     = nowLocal.getUTCHours();
const day      = nowLocal.getUTCDay();

if (day === 0) return [];
if (hour < hStart || hour >= hEnd) return [];

return [{ json: payload }];

// Pure JS HMAC-SHA256 — no external modules needed
function _sha256(data){const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];let b=[...data];const ml=b.length*8;b.push(0x80);while(b.length%64!==56)b.push(0);for(let i=3;i>=0;i--)b.push(0);for(let i=3;i>=0;i--)b.push((ml>>>(i*8))&0xff);const ro=(x,n)=>(x>>>n)|(x<<(32-n));let a=0x6a09e667,bv=0xbb67ae85,c=0x3c6ef372,d=0xa54ff53a,e=0x510e527f,f=0x9b05688c,g=0x1f83d9ab,h=0x5be0cd19;for(let i=0;i<b.length;i+=64){const W=[];for(let j=0;j<16;j++)W[j]=(b[i+j*4]<<24)|(b[i+j*4+1]<<16)|(b[i+j*4+2]<<8)|b[i+j*4+3];for(let j=16;j<64;j++){const s0=ro(W[j-15],7)^ro(W[j-15],18)^(W[j-15]>>>3);const s1=ro(W[j-2],17)^ro(W[j-2],19)^(W[j-2]>>>10);W[j]=(W[j-16]+s0+W[j-7]+s1)>>>0;}let[aa,bb,cc,dd,ee,ff,gg,hh]=[a,bv,c,d,e,f,g,h];for(let j=0;j<64;j++){const S1=ro(ee,6)^ro(ee,11)^ro(ee,25);const ch=(ee&ff)^(~ee&gg);const t1=(hh+S1+ch+K[j]+W[j])>>>0;const S0=ro(aa,2)^ro(aa,13)^ro(aa,22);const maj=(aa&bb)^(aa&cc)^(bb&cc);const t2=(S0+maj)>>>0;hh=gg;gg=ff;ff=ee;ee=(dd+t1)>>>0;dd=cc;cc=bb;bb=aa;aa=(t1+t2)>>>0;}a=(a+aa)>>>0;bv=(bv+bb)>>>0;c=(c+cc)>>>0;d=(d+dd)>>>0;e=(e+ee)>>>0;f=(f+ff)>>>0;g=(g+gg)>>>0;h=(h+hh)>>>0;}const out=[];[a,bv,c,d,e,f,g,h].forEach(v=>{for(let i=3;i>=0;i--)out.push((v>>>(i*8))&0xff)});return out;}
function _hmac256(key,msg){let k=[...key];if(k.length>64)k=_sha256(k);while(k.length<64)k.push(0);return _sha256([...k.map(b=>b^0x5c),..._sha256([...k.map(b=>b^0x36),...msg])]);}
function _enc(s){const b=[];for(let i=0;i<s.length;i++){const c=s.charCodeAt(i);if(c<128)b.push(c);else if(c<2048){b.push(192|(c>>6));b.push(128|(c&63));}else{b.push(224|(c>>12));b.push(128|((c>>6)&63));b.push(128|(c&63));}}return b;}
const cfg     = $('Config').first().json;
const payload = $('Webhook').first().json.body;
const orgArr  = $('Fetch Org Config').all();
const org     = orgArr[0]?.json ?? {};

// Voice (SIP) credentials
const voiceOut   = org.channel_config?.voice_outbound ?? {};
const trunkId    = voiceOut.livekit_sip_outbound_trunk_id;
const fromNumber = voiceOut.from_number || '';
const voiceAvailable = !!trunkId && !!payload.phone;

// WA credentials
const wa        = org.channel_config?.whatsapp ?? {};
const waCreds   = wa.credentials ?? {};
const waPhoneId = waCreds.phone_number_id || '';
const waToken   = waCreds.access_token || '';
const waActive  = !!wa.active && !!waPhoneId && !!waToken;

if (!voiceAvailable && !waActive) {
  console.error('No voice SIP and no WA for org: ' + payload.org_id);
  return [];
}

function base64url(s) {
  return Buffer.from(s).toString('base64url');
}

let jwt = '';
let roomName = '';
let agentMetadata = '';

if (voiceAvailable) {
  const roomName = 'wf-' + payload.run_id.replace(/-/g,'').slice(0, 12);
const now    = Math.floor(Date.now() / 1000);
  const header = base64url(JSON.stringify({ alg:'HS256', typ:'JWT' }));
  const claims = base64url(JSON.stringify({
    iss: cfg.LIVEKIT_API_KEY,
    sub: 'n8n-outbound-s1',
    exp: now + 600,
    nbf: now,
    video: { roomCreate: true, roomAdmin: true, room: roomName },
    sip:   { admin: true, call: true },
  }));
  const sig = Buffer.from(_hmac256(_enc(cfg.LIVEKIT_API_SECRET), _enc(header + '.' + claims))).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
  jwt = header + '.' + claims + '.' + sig;
  roomName = 'wf-' + payload.run_id.replace(/-/g,'').slice(0, 12);
}

const contactName = payload.contact_data?.name || '';
const lang        = org.ai_persona?.language || 'tr';
const waTemplate  = payload.config?.wa_template || 're_engagement_v1';
const LANG_MAP = { en: 'en_US', de: 'de', tr: 'tr', ar: 'ar', fr: 'fr_FR' };
const templateLang = LANG_MAP[lang] || lang;
const voiceWaitMinutes = payload.config?.voice_wait_minutes || 60;

agentMetadata = JSON.stringify({
  organization_id: payload.org_id,
  scenario:        'first_contact',
  contact_id:      payload.contact_data?.contact_id || null,
  lead_id:         payload.contact_data?.lead_id || null,
  phone_to:        payload.phone,
  contact_name:    contactName,
  run_id:          payload.run_id,
  callback_url:    payload.callback_url,
  lang: payload.contact_data?.preferred_language || (orgArr[0]?.json?.ai_persona?.language) || 'tr',
});

return [{ json: {
  voice_available:    voiceAvailable,
  jwt,
  trunk_id:           trunkId || '',
  from_number:        fromNumber,
  room_name:          roomName,
  phone:              payload.phone,
  contact_name:       contactName,
  run_id:             payload.run_id,
  callback_url:       payload.callback_url,
  agent_metadata:     agentMetadata,
  wa_active:          waActive,
  wa_phone_id:        waPhoneId,
  wa_token:           waToken,
  wa_template:        waTemplate,
  wa_template_lang:   templateLang,
  wa_to_phone:        payload.phone.replace(/^\+/, ''),
  voice_wait_minutes: voiceWaitMinutes,
} }];

const cfg   = $('Config').first().json;
const runId = $('Build Voice + WA Payload').first().json.run_id;

const res    = await fetch(
  `${cfg.SUPABASE_URL}/rest/v1/workflow_runs?id=eq.${runId}&select=status&limit=1`,
  { headers: { apikey: cfg.SUPABASE_SERVICE_KEY, Authorization: `Bearer ${cfg.SUPABASE_SERVICE_KEY}` } }
);
const data   = await res.json();
const status = data[0]?.status || 'unknown';

return [{ json: { run_status: status, voice_succeeded: status === 'success' } }];

